import React, { useState, useEffect } from 'react';
import axios from 'axios';

const ProductForm = ({ refreshProducts, selectedProduct, updateProduct }) => {
    const [product, setProduct] = useState({
        nome: '',
        descricao: '',
        codigo: '',
        categoria: '',
        preco: '',
        quantidade_minima: ''
    });

    useEffect(() => {
        if (selectedProduct) {
            setProduct(selectedProduct);
        } else {
            setProduct({
                nome: '',
                descricao: '',
                codigo: '',
                categoria: '',
                preco: '',
                quantidade_minima: ''
            });
        }
    }, [selectedProduct]);

    const handleChange = (e) => {
        setProduct({ ...product, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        const productData = {
            ...product,
            preco: parseFloat(product.preco),
            quantidade_minima: parseInt(product.quantidade_minima),
        };

        if (selectedProduct) {
            await updateProduct(productData); // Atualiza produto existente
        } else {
            await axios.post('http://127.0.0.1:8000/api/produtos/', productData);
            refreshProducts(); // Atualiza a lista de produtos
        }

        // Limpa o formulário após o cadastro ou atualização
        setProduct({
            nome: '',
            descricao: '',
            codigo: '',
            categoria: '',
            preco: '',
            quantidade_minima: ''
        });
    };

    return (
        <form onSubmit={handleSubmit}>
            <input name="nome" value={product.nome} placeholder="Nome" onChange={handleChange} required />
            <input name="descricao" value={product.descricao} placeholder="Descrição" onChange={handleChange} required />
            <input name="codigo" value={product.codigo} placeholder="Código" onChange={handleChange} required />
            <input name="categoria" value={product.categoria} placeholder="Categoria" onChange={handleChange} required />
            <input type="number" name="preco" value={product.preco} placeholder="Preço" onChange={handleChange} required />
            <input type="number" name="quantidade_minima" value={product.quantidade_minima} placeholder="Quantidade Mínima" onChange={handleChange} required />
            <button type="submit">{selectedProduct ? "Atualizar Produto" : "Adicionar Produto"}</button>
        </form>
    );
};

export default ProductForm;
